const AdminTestimonials = () => {
  return (
    <section className="container mx-auto px-4 py-12">
      <h1 className="section-title">Manage Testimonials</h1>
      <p className="section-subtitle">Review and approve client feedback before publishing it on the website.</p>
      <div className="card p-8 mt-8">
        <p className="text-gray-600">Use this view to moderate submitted testimonials and highlight the best customer stories.</p>
      </div>
    </section>
  );
};

export default AdminTestimonials;
